function pruneTdWorkflowJobs() {
  const now = Date.now();
  for (const [id, job] of tdWorkflowJobs) {
    const t = new Date(job.created_at || 0).getTime();
    if (now - t > LISTING_SYNC_JOB_TTL_MS) tdWorkflowJobs.delete(id);
