    const walk = (node, acc) => {
      if (!node) return acc;
      if (node.nodeType === 1) {
        if (node.tagName === 'INPUT' && node.type === 'file') acc.push(node);
        if (node.shadowRoot) walk(node.shadowRoot, acc);
