#!/usr/bin/env node
/**
 * Attention / flow backtest on real historical OHLCV.
 *
 * - P&L comes only from price paths + fees + slippage (no biased coin flips).
 * - "Hype + buying" is proxied with past-only volume surge + momentum (causal).
 * - Exit ladder targets 65% and 75% of a volatility-scaled move (ATR at entry;
 *   no lookahead — projection uses information available at entry).
 * - Multiple virtual bots trade different symbols so capital is not concentrated
 *   in one name (diversification / impact spread, not evasion).
 * - After each trade, logs outcome and nudges entry strictness from recent
 *   performance (simple adaptive learning; journal JSONL for offline analysis).
 *
 * Usage:
 *   node scripts/attention-momentum-backtest.mjs
 *   node scripts/attention-momentum-backtest.mjs --days 400 --bots 4 --seed 7
 *   node scripts/attention-momentum-backtest.mjs --csv ./data/ohlcv/BTCUSDT.csv
 *
 * CSV format (header optional): time_ms,open,high,low,close,volume
 *
 * @ssot docs/projects/AMENDMENT_21_LIFEOS_CORE.md
 */

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');
const DEFAULT_OUT = path.join(ROOT, 'logs', 'attention-backtest-trades.jsonl');

// ── Seeded RNG (reproducible runs) ─────────────────────────────────────────
function mulberry32(a) {
  return function () {
    let t = (a += 0x6d2b79f5);
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function parseArgs(argv) {
  const o = {
    days: 500,
    bots: 4,
    seed: 42,
    symbols: ['BTCUSDT', 'ETHUSDT', 'SOLUSDT', 'BNBUSDT'],
    interval: '4h',
    csv: null,
    out: DEFAULT_OUT,
    initialPerBot: 500,
    feeBps: 10,
    slipBps: 5,
    volThreshold: 1.75,
    atrMult: 3,
    regimeLookback: 30,
    warmBars: 120,
  };
  for (let i = 2; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--days') o.days = Number(argv[++i]);
    else if (a === '--bots') o.bots = Math.max(1, Number(argv[++i]));
    else if (a === '--seed') o.seed = Number(argv[++i]);
    else if (a === '--symbols') o.symbols = argv[++i].split(',').map((s) => s.trim().toUpperCase());
    else if (a === '--interval') o.interval = argv[++i];
    else if (a === '--csv') o.csv = argv[++i];
    else if (a === '--out') o.out = argv[++i];
    else if (a === '--per-bot') o.initialPerBot = Number(argv[++i]);
    else if (a === '--fee-bps') o.feeBps = Number(argv[++i]);
    else if (a === '--slip-bps') o.slipBps = Number(argv[++i]);
  }
  return o;
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

async function fetchBinanceKlines(symbol, interval, startMs, endMs) {
  const url = new URL('https://api.binance.com/api/v3/klines');
  url.searchParams.set('symbol', symbol);
  url.searchParams.set('interval', interval);
  url.searchParams.set('startTime', String(startMs));
  url.searchParams.set('endTime', String(endMs));
  url.searchParams.set('limit', '1000');
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Binance ${res.status}: ${await res.text()}`);
  return res.json();
}

function klineRowToBar(row) {
  return {
    t: row[0],
    o: Number(row[1]),
    h: Number(row[2]),
    l: Number(row[3]),
    c: Number(row[4]),
    v: Number(row[5]),
  };
}

async function loadBarsLive(symbol, interval, daysBack) {
  const end = Date.now();
  const approxMsPerBar =
    interval === '1h' ? 3600000 : interval === '4h' ? 14400000 : interval === '1d' ? 86400000 : 14400000;
  const needBars = Math.ceil((daysBack * 86400000) / approxMsPerBar) + 200;
  let start = end - daysBack * 86400000;
  const all = [];
  let guard = 0;
  while (all.length < needBars && guard < 80) {
    guard++;
    const chunk = await fetchBinanceKlines(symbol, interval, start, end);
    if (!chunk.length) break;
    for (const row of chunk) all.push(klineRowToBar(row));
    const lastT = chunk[chunk.length - 1][0];
    start = lastT + 1;
    await sleep(120);
  }
  all.sort((a, b) => a.t - b.t);
  const dedup = [];
  let prev = -1;
  for (const b of all) {
    if (b.t !== prev) dedup.push(b);
    prev = b.t;
  }
  return dedup;
}

function loadBarsCsv(filePath) {
  const raw = fs.readFileSync(filePath, 'utf8').trim().split('\n');
  const bars = [];
  for (let i = 0; i < raw.length; i++) {
    const line = raw[i].trim();
    if (!line || line.startsWith('#')) continue;
    const parts = line.split(/[,\t]/);
    if (parts.length < 6) continue;
    if (i === 0 && /open|high/i.test(line)) continue;
    const t = Number(parts[0]);
    bars.push({
      t,
      o: Number(parts[1]),
      h: Number(parts[2]),
      l: Number(parts[3]),
      c: Number(parts[4]),
      v: Number(parts[5]),
    });
  }
  return bars.sort((a, b) => a.t - b.t);
}

function sma(arr, i, len) {
  if (i < len - 1) return null;
  let s = 0;
  for (let j = i - len + 1; j <= i; j++) s += arr[j];
  return s / len;
}

function atr(bars, i, len) {
  if (i < 1 || i < len) return null;
  let s = 0;
  for (let j = i - len + 1; j <= i; j++) {
    const tr = Math.max(
      bars[j].h - bars[j].l,
      Math.abs(bars[j].h - bars[j - 1].c),
      Math.abs(bars[j].l - bars[j - 1].c),
    );
    s += tr;
  }
  return s / len;
}

function volumeAvg(bars, i, len) {
  if (i < len - 1) return null;
  let s = 0;
  for (let j = i - len + 1; j <= i; j++) s += bars[j].v;
  return s / len;
}

/** Past-only regime at bar i (no future). */
function regimeAt(bars, i, lookback) {
  if (i < lookback + 1) return 'unknown';
  const a = bars[i - lookback].o;
  const b = bars[i - 1].c;
  const r = (b - a) / a;
  if (r > 0.025) return 'bull';
  if (r < -0.025) return 'bear';
  return 'chop';
}

function applyCosts(price, bps, feeBps, slipBps, buy) {
  const adj = buy ? 1 + (feeBps + slipBps) / 10000 : 1 - (feeBps + slipBps) / 10000;
  return price * adj;
}

function createLearner() {
  return {
    byRegime: Object.create(null),
    recentR: [],
    volAdjust: 0,
    record(trade) {
      const r = trade.regime || 'unknown';
      if (!this.byRegime[r]) this.byRegime[r] = { n: 0, wins: 0, pnl: 0 };
      this.byRegime[r].n++;
      this.byRegime[r].pnl += trade.pnlUsd;
      if (trade.pnlUsd > 0) this.byRegime[r].wins++;
      this.recentR.push(trade.rMultiple);
      if (this.recentR.length > 30) this.recentR.shift();
      if (this.recentR.length >= 15) {
        const avg = this.recentR.reduce((a, b) => a + b, 0) / this.recentR.length;
        if (avg < -0.05) this.volAdjust = Math.min(0.5, this.volAdjust + 0.03);
        else if (avg > 0.15) this.volAdjust = Math.max(-0.25, this.volAdjust - 0.02);
      }
    },
  };
}

function runBotOnBars(opts, bars, botId, symbol, rng, learner) {
  const {
    feeBps,
    slipBps,
    volThreshold,
    atrMult,
    regimeLookback,
    warmBars,
    initialPerBot,
  } = opts;

  let cash = initialPerBot;
  let qty = 0;
  let entryPx = 0;
  let leg = 0;
  let t1 = 0;
  let t2 = 0;
  let trail = 0;
  let highWM = 0;
  let stopPx = 0;
  const trades = [];

  const sma20 = (i) => sma(bars.map((b) => b.c), i, 20);
  const sma50 = (i) => sma(bars.map((b) => b.c), i, 50);
  const volAvg20 = (i) => volumeAvg(bars, i, 20);

  for (let i = warmBars; i < bars.length - 2; i++) {
    const regime = regimeAt(bars, i, regimeLookback);
    const effVolTh = volThreshold + learner.volAdjust + botId * 0.04;

    if (qty <= 0) {
      const c = bars[i].c;
      const v = bars[i].v;
      const va = volAvg20(i);
      const s20 = sma20(i);
      const s50 = sma50(i);
      const a = atr(bars, i, 14);
      if (va == null || s20 == null || s50 == null || a == null) continue;

      const volRatio = v / va;
      const mom = c > s20 && c >= s50 * 0.998;
      const impulse = c / bars[i].l > 1.002 || (i >= 4 && c > bars[i - 4].c);

      if (volRatio >= effVolTh && mom && impulse) {
        const entryBar = i + 1;
        const px = bars[entryBar].o;
        const fill = applyCosts(px, 0, feeBps, slipBps, true);
        const spend = cash * 0.98;
        const q = spend / fill;
        if (q * fill < 5) continue;
        cash -= q * fill;
        qty = q;
        entryPx = fill;
        leg = 0;
        const atrNow = atr(bars, i, 14);
        const move = atrMult * atrNow;
        t1 = entryPx + 0.65 * move;
        t2 = entryPx + 0.75 * move;
        stopPx = entryPx - 1.25 * atrNow;
        highWM = entryPx;
        trail = 0;
      }
    } else {
      const b = bars[i];
      highWM = Math.max(highWM, b.h);
      const a = atr(bars, i, 14) ?? atr(bars, i - 1, 14) ?? 0;
