        const fill = applyCosts(b.c, 0, feeBps, slipBps, false);
        cash += q * fill;
        qty -= q;
        if (qty < 1e-12) qty = 0;
        const pnlUsd = q * (fill - entryPx);
        const risk = Math.max(entryPx - stopPx, entryPx * 0.01) * q;
        const rMultiple = risk > 0 ? pnlUsd / risk : 0;
        trades.push({
          botId,
          symbol,
          exitBar: i,
          exitTime: b.t,
          reason,
          pnlUsd,
          rMultiple,
          regime,
          leg: ++leg,
        });
        learner.record(trades[trades.length - 1]);
      };

      if (b.l <= stopPx && qty > 0) {
        const fill = applyCosts(Math.min(stopPx, b.o), 0, feeBps, slipBps, false);
        const q = qty;
        cash += q * fill;
        qty = 0;
        const pnlUsd = q * (fill - entryPx);
        const risk = Math.max(entryPx - stopPx, entryPx * 0.01) * q;
        const rMultiple = risk > 0 ? pnlUsd / risk : 0;
        trades.push({
          botId,
          symbol,
          exitBar: i,
          exitTime: b.t,
          reason: 'stop',
          pnlUsd,
          rMultiple,
          regime,
          leg: 9,
        });
        learner.record(trades[trades.length - 1]);
        continue;
      }

      if (leg < 1 && b.h >= t1) sellFrac(0.35, 'partial_65pct_projected');
      else if (leg < 2 && b.h >= t2) sellFrac(0.5, 'partial_75pct_projected');
