  }

  if (qty > 0) {
    const last = bars[bars.length - 1];
    const fill = applyCosts(last.c, 0, feeBps, slipBps, false);
    cash += qty * fill;
    const pnlUsd = qty * (fill - entryPx);
    const risk = Math.max(entryPx - stopPx, entryPx * 0.01) * qty;
    const rMultiple = risk > 0 ? pnlUsd / risk : 0;
