      pnlUsd,
      rMultiple,
      regime: regimeAt(bars, bars.length - 1, regimeLookback),
      leg: 9,
    });
    learner.record(trades[trades.length - 1]);
  }

  return { finalCash: cash, trades };
}

async function main() {
  const opts = parseArgs(process.argv);
  fs.mkdirSync(path.dirname(opts.out), { recursive: true });
  const rng = mulberry32(opts.seed >>> 0);
  const learner = createLearner();

  const symbols = opts.symbols.slice(0, opts.bots);
  while (symbols.length < opts.bots) symbols.push(opts.symbols[symbols.length % opts.symbols.length]);

  console.log('Attention-momentum backtest (real OHLCV, causal signals)');
  console.log(JSON.stringify({ ...opts, symbols }, null, 2));

  const series = [];
  if (opts.csv) {
    const bars = loadBarsCsv(opts.csv);
    series.push({ symbol: path.basename(opts.csv, '.csv'), bars });
  } else {
    for (const sym of symbols) {
      process.stdout.write(`Fetching ${sym} … `);
      const bars = await loadBarsLive(sym, opts.interval, opts.days);
      console.log(`${bars.length} bars`);
      series.push({ symbol: sym, bars });
    }
  }

  let grandTrades = [];
  const summaries = [];

  for (let b = 0; b < opts.bots; b++) {
    const { symbol, bars } = series[opts.csv ? 0 : b];
    if (bars.length < opts.warmBars + 50) {
      console.warn(`Skip bot ${b}: insufficient bars for ${symbol}`);
      continue;
    }
    const { finalCash, trades } = runBotOnBars({ ...opts, rng }, bars, b, symbol, rng, learner);
    const pnl = finalCash - opts.initialPerBot;
    summaries.push({ botId: b, symbol, initial: opts.initialPerBot, finalCash, pnlUsd: pnl, trades: trades.length });
    grandTrades = grandTrades.concat(trades);
  }

  const fd = fs.openSync(opts.out, 'a');
  for (const t of grandTrades) {
    fs.writeSync(fd, JSON.stringify({ ...t, ts: Date.now(), seed: opts.seed }) + '\n');
  }
  fs.closeSync(fd);

  console.log('\n--- Per bot ---');
  for (const s of summaries) {
    console.log(
      `bot ${s.botId} ${s.symbol}: $${s.initial.toFixed(2)} → $${s.finalCash.toFixed(2)} (${s.pnlUsd >= 0 ? '+' : ''}${s.pnlUsd.toFixed(2)}) trades=${s.trades}`,
    );
  }
  const totalPnl = summaries.reduce((a, s) => a + s.pnlUsd, 0);
  console.log(`\nTotal P&L (all bots): ${totalPnl >= 0 ? '+' : ''}$${totalPnl.toFixed(2)}`);
  console.log('Learning state by regime:', learner.byRegime);
  console.log(`Vol threshold adjust from learning: ${learner.volAdjust.toFixed(3)} (applied inside run; re-run for full walk-forward)`);
  console.log(`\nTrade journal appended: ${opts.out}`);
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});

