function runBotOnBars(opts, bars, botId, symbol, learner) {
  const { feeBps, slipBps, volThreshold, atrMult, regimeLookback, warmBars, initialPerBot } = opts;

  let cash = initialPerBot;
  let qty = 0;
  let entryPx = 0;
  let entryBarIdx = 0;
  let leg = 0;
  let t1 = 0;
  let t2 = 0;
  let trail = 0;
  let highWM = 0;
  let stopPx = 0;
  let regimeAtEntry = 'unknown';
  const trades = [];
  const closes = bars.map((b) => b.c);

  const sma20 = (i) => sma(closes, i, 20);
  const sma50 = (i) => sma(closes, i, 50);
  const volAvg20 = (i) => volumeAvg(bars, i, 20);

  const riskDenom = () => Math.max(entryPx - stopPx, entryPx * 0.01);

  const closeRoundTrip = (i, b, primaryReason, partialFills) => {
    const totalPnl = partialFills.reduce((s, x) => s + x.pnlUsd, 0);
    const initialNotional = partialFills.reduce((s, x) => s + x.qty * entryPx, 0) || entryPx * 1e-12;
    const rMultiple = riskDenom() > 0 ? totalPnl / (riskDenom() * (initialNotional / entryPx || 1)) : 0;
    const row = {
      botId,
      symbol,
      entryBar: entryBarIdx,
      exitBar: i,
      exitTime: b.t,
      primaryReason,
      pnlUsd: totalPnl,
      rMultiple,
      regimeAtEntry,
      partialFills,
    };
    trades.push(row);
    learner.record({ ...row, regime: regimeAtEntry });
  };

  for (let i = warmBars; i < bars.length - 2; i++) {
    const regime = regimeAt(bars, i, regimeLookback);
    const effVolTh = volThreshold + learner.volAdjust + botId * 0.04;

    if (qty <= 0) {
      const c = bars[i].c;
      const v = bars[i].v;
      const va = volAvg20(i);
      const s20 = sma20(i);
      const s50 = sma50(i);
      const a = atr(bars, i, 14);
      if (va == null || s20 == null || s50 == null || a == null) continue;

      const volRatio = v / va;
      const mom = c > s20 && c >= s50 * 0.998;
      const impulse = c / bars[i].l > 1.002 || (i >= 4 && c > bars[i - 4].c);

      if (volRatio >= effVolTh && mom && impulse) {
        const entryBar = i + 1;
        const px = bars[entryBar].o;
        const fill = applyCosts(px, feeBps, slipBps, true);
        const spend = cash * 0.98;
        const q = spend / fill;
        if (q * fill < 5) continue;
        cash -= q * fill;
        qty = q;
        entryPx = fill;
        entryBarIdx = entryBar;
        regimeAtEntry = regimeAt(bars, i, regimeLookback);
        leg = 0;
        const atrNow = atr(bars, i, 14);
        const move = atrMult * atrNow;
        t1 = entryPx + 0.65 * move;
        t2 = entryPx + 0.75 * move;
        stopPx = entryPx - 1.25 * atrNow;
        highWM = entryPx;
        i = entryBar;
      }
    } else {
      const b = bars[i];
      highWM = Math.max(highWM, b.h);
      const a = atr(bars, i, 14) ?? atr(bars, i - 1, 14) ?? 0;
      trail = highWM - 0.55 * a;

      const partialFills = [];

      const sellFrac = (fraction, reason) => {
        if (qty <= 0 || fraction <= 0) return;
        const qSell = qty * fraction;
        const fill = applyCosts(b.c, feeBps, slipBps, false);
        cash += qSell * fill;
        qty -= qSell;
        if (qty < 1e-12) qty = 0;
        partialFills.push({ reason, pnlUsd: qSell * (fill - entryPx), qty: qSell, bar: i });
        leg += 1;
      };

      if (b.l <= stopPx && qty > 0) {
        const fill = applyCosts(stopPx, feeBps, slipBps, false);
        const q = qty;
        cash += q * fill;
        partialFills.push({ reason: 'stop', pnlUsd: q * (fill - entryPx), qty: q, bar: i });
        qty = 0;
        closeRoundTrip(i, b, 'stop', partialFills);
        continue;
      }

      while (qty > 0 && leg < 1 && b.h >= t1) sellFrac(0.35, 'partial_65pct_projected');
      while (qty > 0 && leg < 2 && b.h >= t2) sellFrac(0.5, 'partial_75pct_projected');

      if (qty > 0 && leg >= 2) {
        if (b.c < trail) sellFrac(1, 'trail_exit');
        else if (sma20(i) != null && b.c < sma20(i)) sellFrac(1, 'trend_exit_sma20');
      }

      if (qty <= 0 && partialFills.length) {
        const primary = partialFills[partialFills.length - 1].reason;
        closeRoundTrip(i, b, primary, partialFills);
      }
    }
  }

  if (qty > 0) {
    const last = bars[bars.length - 1];
    const fill = applyCosts(last.c, feeBps, slipBps, false);
    const q = qty;
    const partialFills = [{ reason: 'eod_close', pnlUsd: q * (fill - entryPx), qty: q, bar: bars.length - 1 }];
    cash += q * fill;
    qty = 0;
    closeRoundTrip(bars.length - 1, last, 'eod_close', partialFills);
  }

  return { finalCash: cash, trades };
}

