```javascript
const KRAKEN_PAIR = {
  BTCUSDT: 'XXBTZUSD',
  ETHUSDT: 'XETHZUSD',
  SOLUSDT: 'SOLUSD',
  BNBUSDT: 'BNBUSD',
};

function intervalToKrakenMinutes(interval) {
  if (interval === '1h') return 60;
  if (interval === '4h') return 240;
  if (interval === '1d') return 1440;
  return 240;
}

async function loadBarsKraken(symbol, interval, daysBack) {
  const pair = KRAKEN_PAIR[symbol];
  if (!pair) throw new Error(`No Kraken mapping for ${symbol}; use --csv`);
  const intervalMin = intervalToKrakenMinutes(interval);
  const startSec = Math.floor(Date.now() / 1000) - daysBack * 86400;
  const endSec = Math.floor(Date.now() / 1000);
  const allMap = new Map();
  let since = startSec;
  let guard = 0;
  while (guard++ < 150) {
    const url = new URL('https://api.kraken.com/0/public/OHLC');
    url.searchParams.set('pair', pair);
    url.searchParams.set('interval', String(intervalMin));
    url.searchParams.set('since', String(since));
    const res = await fetch(url);
    if (!res.ok) throw new Error(`Kraken ${res.status}`);
    const data = await res.json();
    if (data.error?.length) throw new Error(data.error.join(', '));
    const key = Object.keys(data.result).find((k) => k !== 'last');
    const rows = data.result[key];
    if (!rows?.length) break;
    for (const r of rows) {
      const ts = r[0] * 1000;
      allMap.set(ts, {
        t: ts,
        o: Number(r[1]),
        h: Number(r[2]),
        l: Number(r[3]),
        c: Number(r[4]),
        v: Number(r[5]),
      });
    }
    const newest = rows[rows.length - 1][0];
    if (newest >= endSec) break;
    since = newest + 1;
    if (rows.length < 720) break;
    await sleep(150);
  }
  const sorted = [...allMap.keys()].sort((a, b) => a - b).map((k) => allMap.get(k));
  return sorted;
}

async function loadBarsForSymbol(symbol, interval, daysBack) {
  try {
    return await loadBarsLive(symbol, interval, daysBack);
  } catch (e) {
    const msg = String(e.message || e);
    if (msg.includes('451') || msg.includes('restricted')) {
      console.warn(`  (Binance blocked; Kraken USD for ${symbol})`);
      return loadBarsKraken(symbol, interval, daysBack);
    }
    throw e;
  }
}
```

Note: Kraken row r[5] is vwap - volume is r[6] in Kraken docs:
[time, open, high, low, close, vwap, volume, count]

So:
o=r[1], h=r[2], l=r[3], c=r[4], v=r[6]

Fix my mapping - I used r[5] for volume wrong.

```javascript
v: Number(r[6]),
```

