        trades: minLevScan.trades,
        endCash: minLevScan.endCash,
        trial: 'formula-random-then-min-leverage',
        minLeverageUsed: minLevScan.lev,
      };
    }
  }
  return {
    best,
    firstHitTarget,
    minLevScan,
    target,
    trials,
    minTrades,
    mode: opts.optimizeMode,
    allowLeverage: opts.optimizeAllowLeverage,
  };
}

