```javascript
#!/usr/bin/env node
/**
 * Runs multiple causal strategies on the same OHLCV, same fee/slip model.
 * Ranks by a simple reliability proxy: returnMult / (1 + maxDrawdown).
 *
 * Not investment advice. Sports / casino edges are not simulated here —
 * add your own CSV outcomes if you model them.
 *
 * @ssot docs/projects/AMENDMENT_21_LIFEOS_CORE.md
 */

import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import {
  loadBarsForSymbol,
  loadBarsCsv,
  runBotOnBarsSlice,
  DEFAULT_FORMULA,
  effectiveWarmBars,
  createLearner,
  applyCosts,
  sma,
} from './attention-momentum-backtest.mjs';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, '..');
const OUT = path.join(ROOT, 'logs', 'strategy-benchmark-suite.json');

function parseArgs(argv) {
  const o = {
    symbols: ['BTCUSDT', 'ETHUSDT', 'SOLUSDT', 'BNBUSDT'],
    days: 500,
    interval: '4h',
    capital: 500,
    feeBps: 10,
    slipBps: 5,
    warm: 120,
    csv: null,
  };
  for (let i = 2; i < argv.length; i++) {
    const a = argv[i];
    if (a === '--symbols') o.symbols = argv[++i].split(',').map((s) => s.trim().toUpperCase());
    else if (a === '--days') o.days = Number(argv[++i]);
    else if (a === '--csv') o.csv = argv[++i];
    else if (a === '--capital') o.capital = Number(argv[++i]);
  }
  return o;
}

function maxDrawdown(equity) {
  let peak = equity[0] || 1;
  let maxDd = 0;
  for (const e of equity) {
    peak = Math.max(peak, e);
    if (peak > 0) maxDd = Math.max(maxDd, (peak - e) / peak);
  }
  return maxDd;
}

function rsi(closes, i, period) {
  if (i < period) return null;
  let gain = 0;
  let loss = 0;
  for (let j = i - period + 1; j <= i; j++) {
    const ch = closes[j] - closes[j - 1];
    if (ch >= 0) gain += ch;
    else loss -= ch;
  }
  const ag = gain / period;
  const al = loss / period;
  if (al === 0) return 100;
  return 100 - 100 / (1 + ag / al);
}

function markEq(cash, qty, px) {
  return cash + qty * px;
}

/** Generic long/flat backtest with next-bar open fills, 98% deploy, same fees */
function runLongFlat(bars, opts, { warm, onBar }) {
  const { feeBps, slipBps, initialPerBot } = opts;
  let cash = initialPerBot;
  let qty = 0;
  const equity = [];
  let trades = 0;
  const closes = bars.map((b) => b.c);

  for (let i = warm; i < bars.length - 1; i++) {
    const action = onBar(bars, closes, i, qty > 0);
    const mpx = bars[i].c;
    equity.push(markEq(cash, qty, mpx));
    if (action === 'buy' && qty <= 0) {
      const next = i + 1;
      const fill = applyCosts(bars[next].o, feeBps, slipBps, true);
      const spend = cash * 0.98;
      const q = spend / fill;
      if (q * fill < Math.max(0.2, initialPerBot * 0.02)) continue;
      cash -= q * fill;
      qty = q;
      trades++;
    } else if (action === 'sell' && qty > 0) {
      const next = i + 1;
      const fill = applyCosts(bars[next].o, feeBps, slipBps, false);
      cash += qty * fill;
      qty = 0;
      trades++;
    }
  }
  const last = bars[bars.length - 1];
  const lf = applyCosts(last.c, feeBps, slipBps, false);
  const finalCash = cash + qty * lf;
  return { finalCash, trades, equity, maxDd: maxDrawdown(equity) };
}

function strategyBuyHold(bars, baseOpts, warm) {
  let entered = false;
  return runLongFlat(bars, baseOpts, {
    warm,
    onBar(bars, closes, i, holding) {
      if (!holding && !entered) {
        entered = true;
        return 'buy';
      }
      return 'hold';
    },
  });
}

Fix buy_hold: should only buy once at first bar - the onBar returns buy once. But runLongFlat will try buy every bar until qty>0 - first iteration buy, then holding true - need action 'hold'. onBar when holding true for buy_hold should return nothing that sells until end - we flatten at end by finalCash including qty* last - good.

Actually first bar: holding false, entered true, return buy - good.
Second bar: holding true - onBar(..., true) - return undefined or 'hold' - need to handle

