/**
 * LifeOS Personal Finance — budgets, categories, goals, IPS text (non-advisory mirror layer).
 *
 * @ssot docs/projects/AMENDMENT_21_LIFEOS_CORE.md
 */

export function createLifeOSFinance({ pool }) {
  async function listAccounts(userId) {
    const { rows } = await pool.query(
      `SELECT * FROM lifeos_finance_accounts WHERE user_id=$1 AND active=true ORDER BY name`,
      [userId],
    );
    return rows;
  }

  async function createAccount(userId, { name, account_type, currency, external_ref }) {
    const { rows } = await pool.query(
      `INSERT INTO lifeos_finance_accounts (user_id, name, account_type, currency, external_ref)
       VALUES ($1,$2,$3,COALESCE($4,'USD'),$5) RETURNING *`,
      [userId, name, account_type || 'other', currency, external_ref || null],
    );
    return rows[0];
  }

  async function listCategories(userId) {
    const { rows } = await pool.query(
      `SELECT * FROM lifeos_finance_categories WHERE user_id=$1 ORDER BY sort_order, name`,
      [userId],
    );
    return rows;
  }

  async function createCategory(userId, { name, values_tag, monthly_cap, sort_order }) {
    const { rows } = await pool.query(
      `INSERT INTO lifeos_finance_categories (user_id, name, values_tag, monthly_cap, sort_order)
       VALUES ($1,$2,$3,$4,$5) RETURNING *`,
      [userId, name, values_tag || null, monthly_cap ?? null, sort_order ?? 0],
    );
    return rows[0];
  }

  async function listTransactions(userId, { limit = 100, from, to } = {}) {
    let sql = `SELECT t.*, c.name AS category_name
      FROM lifeos_finance_transactions t
      LEFT JOIN lifeos_finance_categories c ON c.id = t.category_id
      WHERE t.user_id=$1`;
    const p = [userId];
    if (from) {
      p.push(from);
      sql += ` AND t.txn_date >= $${p.length}`;
    }
    if (to) {
      p.push(to);
      sql += ` AND t.txn_date <= $${p.length}`;
    }
    sql += ` ORDER BY t.txn_date DESC, t.id DESC LIMIT ${Math.min(500, Math.max(1, limit))}`;
    const { rows } = await pool.query(sql, p);
    return rows;
  }

  async function createTransaction(userId, { account_id, category_id, amount, txn_date, memo, source }) {
    const { rows } = await pool.query(
      `INSERT INTO lifeos_finance_transactions
        (user_id, account_id, category_id, amount, txn_date, memo, source)
       VALUES ($1,$2,$3,$4,COALESCE($5,CURRENT_DATE),$6,COALESCE($7,'manual')) RETURNING *`,
      [userId, account_id || null, category_id || null, amount, txn_date || null, memo || null, source || 'manual'],
    );
    return rows[0];
  }

  async function summaryMonth(userId, yyyymm) {
    const [y, m] = String(yyyymm || '').split('-').filter(Boolean);
    const monthStart = y && m ? `${y}-${m.padStart(2, '0')}-01` : null;
    if (!monthStart) {
      const { rows: cur } = await pool.query(`SELECT date_trunc('month', CURRENT_DATE)::date AS d`);
      var start = cur[0].d;
    } else {
      start = monthStart;
    }
    const { rows: spend } = await pool.query(
      `SELECT COALESCE(SUM(amount),0)::numeric AS spent
       FROM lifeos_finance_transactions
       WHERE user_id=$1 AND txn_date >= $2::date AND txn_date < ($2::date + INTERVAL '1 month')`,
      [userId, start],
    );
    const { rows: caps } = await pool.query(
      `SELECT name, monthly_cap FROM lifeos_finance_categories WHERE user_id=$1 AND monthly_cap IS NOT NULL`,
      [userId],
    );
    return { month_start: start, net_cents_agnostic: spend[0]?.spent, categories_with_cap: caps };
  }

  async function listGoals(userId) {
    const { rows } = await pool.query(
      `SELECT * FROM lifeos_finance_goals WHERE user_id=$1 ORDER BY target_date NULLS LAST, name`,
      [userId],
    );
    return rows;
  }

  async function upsertGoal(userId, payload) {
    const { id, name, target_amount, current_amount, target_date, dream_id, notes } = payload;
    if (id) {
      const { rows } = await pool.query(
        `UPDATE lifeos_finance_goals SET
          name=COALESCE($2,name), target_amount=COALESCE($3,target_amount),
          current_amount=COALESCE($4,current_amount), target_date=$5, dream_id=$6, notes=$7, updated_at=NOW()
         WHERE id=$1 AND user_id=$8 RETURNING *`,
        [id, name, target_amount, current_amount, target_date || null, dream_id || null, notes || null, userId],
      );
      return rows[0] || null;
    }
    const { rows } = await pool.query(
      `INSERT INTO lifeos_finance_goals (user_id, name, target_amount, current_amount, target_date, dream_id, notes)
       VALUES ($1,$2,$3,COALESCE($4,0),$5,$6,$7) RETURNING *`,
      [userId, name, target_amount ?? null, current_amount, target_date || null, dream_id || null, notes || null],
    );
    return rows[0];
  }

  async function getIps(userId) {
    const { rows } = await pool.query(`SELECT * FROM lifeos_finance_ips WHERE user_id=$1`, [userId]);
    return rows[0] || null;
  }

  async function putIps(userId, { statement_text, risk_notes }) {
    const { rows } = await pool.query(
      `INSERT INTO lifeos_finance_ips (user_id, statement_text, risk_notes)
       VALUES ($1,$2,$3)
       ON CONFLICT (user_id) DO UPDATE SET
         statement_text = EXCLUDED.statement_text,
         risk_notes = EXCLUDED.risk_notes,
         updated_at = NOW()
       RETURNING *`,
      [userId, statement_text ?? '', risk_notes ?? ''],
    );
    return rows[0];
  }

  return {
    listAccounts,
    createAccount,
    listCategories,
    createCategory,
    listTransactions,
    createTransaction,
    summaryMonth,
    listGoals,
    upsertGoal,
    getIps,
    putIps,
  };
}

/**
 * LifeOS Personal Finance API — mirror / clarity only; not investment advice.
 * Mounted at /api/v1/lifeos/finance
 *
 * @ssot docs/projects/AMENDMENT_21_LIFEOS_CORE.md
 */

import express from 'express';
import { createLifeOSFinance } from '../services/lifeos-finance.js';

export function createLifeOSFinanceRoutes({ pool, requireKey, logger }) {
  const router = express.Router();
  const log = logger || console;
  const finance = createLifeOSFinance({ pool });

  async function resolveUserId(handleOrId) {
    if (handleOrId == null || handleOrId === '') return null;
    const s = String(handleOrId).trim();
    if (/^\d+$/.test(s)) {
      const { rows } = await pool.query('SELECT id FROM lifeos_users WHERE id = $1', [s]);
      return rows[0]?.id ?? null;
    }
    const { rows } = await pool.query('SELECT id FROM lifeos_users WHERE user_handle = $1', [s]);
    return rows[0]?.id ?? null;
  }

  router.get('/disclaimer', (_req, res) => {
    res.json({
      ok: true,
      disclaimer:
        'Education and self-reflection only. Not tax, legal, or investment advice. Past simulations do not predict future results.',
    });
  });

  router.get('/accounts', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.query.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error:User not found' });
      res.json({ ok: true, accounts: await finance.listAccounts(userId) });
    } catch (err) {
      log.warn?.(err.message);
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.post('/accounts', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.body.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error: 'User not found' });
      const { name, account_type, currency, external_ref } = req.body;
      if (!name?.trim()) return res.status(400).json({ ok: false, error: 'name required' });
      const row = await finance.createAccount(userId, { name, account_type, currency, external_ref });
      res.status(201).json({ ok: true, account: row });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.get('/categories', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.query.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error: 'User not found' });
      res.json({ ok: true, categories: await finance.listCategories(userId) });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.post('/categories', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.body.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error: 'User not found' });
      const { name, values_tag, monthly_cap, sort_order } = req.body;
      if (!name?.trim()) return res.status(400).json({ ok: false, error: 'name required' });
      const row = await finance.createCategory(userId, { name, values_tag, monthly_cap, sort_order });
      res.status(201).json({ ok: true, category: row });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.get('/transactions', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.query.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error: 'User not found' });
      const rows = await finance.listTransactions(userId, {
        limit: parseInt(req.query.limit || '100', 10),
        from: req.query.from,
        to: req.query.to,
      });
      res.json({ ok: true, transactions: rows });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.post('/transactions', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.body.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error: 'User not found' });
      const { account_id, category_id, amount, txn_date, memo, source } = req.body;
      if (amount == null) return res.status(400).json({ ok: false, error: 'amount required' });
      const row = await finance.createTransaction(userId, {
        account_id,
        category_id,
        amount,
        txn_date,
        memo,
        source,
      });
      res.status(201).json({ ok: true, transaction: row });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.get('/summary', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.query.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error: 'User not found' });
      const s = await finance.summaryMonth(userId, req.query.month);
      res.json({ ok: true, summary: s });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.get('/goals', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.query.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error: 'User not found' });
      res.json({ ok: true, goals: await finance.listGoals(userId) });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.post('/goals', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.body.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error: 'User not found' });
      const row = await finance.upsertGoal(userId, req.body);
      res.json({ ok: true, goal: row });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.get('/ips', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.query.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error: 'User not found' });
      res.json({ ok: true, ips: await finance.getIps(userId) });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.put('/ips', requireKey, async (req, res) => {
    try {
      const userId = await resolveUserId(req.body.user || 'adam');
      if (!userId) return res.status(404).json({ ok: false, error: 'User not found' });
      const row = await finance.putIps(userId, {
        statement_text: req.body.statement_text,
        risk_notes: req.body.risk_notes,
      });
      res.json({ ok: true, ips: row });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  return router;
}

